select o.id, o.user_id, o.out_trade_no, o.open_id, o.amount, o.`status`, o.payment_status, o.created_at, o.paid_at, o.product_id, o.order_type, o.refund_time, o.refund_reason
/*,p.`name` product_name
,a.activity_name
,pi.remark product_identity_name*/

/*,IF(p.`name` IS NOT NULL,p.`name`, IF(a.activity_name IS NOT NULL,a.activity_name,o.product_identity_id)) product_name*/
,IF(p.`name` IS NOT NULL,p.`name`, IF(a.activity_name IS NOT NULL,a.activity_name,IF(pi.remark IS NOT NULL,pi.remark,''))) product_name

,p.images
,IF(p.`name` IS NOT NULL,p.images, IF(a.activity_name IS NOT NULL,1,o.product_identity_id)) images

from zhs_order o
left join zhs_product p on o.product_id = p.id
left join zhs_activity a on o.activity_id = a.id
left join zhs_center_project.zhs_product_identity pi on o.product_identity_id = pi.id

     and o.user_id = #{userId}
     and out_trade_no = #{outTradeNo}
     and open_id = #{openId}
     and amount = #{amount}
     and o.`status` = #{status}
     and o.payment_status = #{paymentStatus}
     and o.created_at = #{createdAt}
     and o.paid_at = #{paidAt}
     and o.product_id = #{productId}
     and o.order_type = #{orderType}
     and o.refund_time = #{refundTime}
     and o.refund_reason = #{refundReason}

        and (p.`name` like CONCAT("%", #{search}, "%")
                 or a.`activity_name` like CONCAT("%", #{search}, "%")
                 /*or pi.`remark` like CONCAT("%", #{search}, "%")*/
                 or o.out_trade_no like CONCAT(#{search}, "%"))


order by o.created_at desc
